import React, { useState, useEffect } from 'react';
import axios from 'axios';

function ExamsManager({ token }) {
  const [exams, setExams] = useState([]);
  const [formData, setFormData] = useState({
    title: '',
    grade: '',
    type: '',
    subject: '',
    amount: '',
    description: '',
    status: 'active'
  });
  const [editingId, setEditingId] = useState(null);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');

  useEffect(() => {
    loadExams();
  }, []);

  const loadExams = async () => {
    try {
      const response = await axios.get('/admin/exams');
      setExams(response.data);
    } catch (err) {
      setMessage('Failed to load exams');
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    const data = new FormData(e.target);
    try {
      if (editingId) {
        await axios.put(`/admin/exams/${editingId}`, data, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        setMessage('Exam updated');
      } else {
        await axios.post('/admin/exams', data, {
          headers: { 'Content-Type': 'multipart/form-data' }
        });
        setMessage('Exam created');
      }
      loadExams();
      setFormData({ title: '', grade: '', type: '', subject: '', amount: '', description: '', status: 'active' });
      setEditingId(null);
    } catch (err) {
      setMessage(err.response?.data?.error || 'Error');
    }
    setLoading(false);
  };

  const editExam = (exam) => {
    setFormData({
      title: exam.title,
      grade: exam.grade,
      type: exam.type,
      subject: exam.subject,
      amount: exam.amount,
      description: exam.description || '',
      status: exam.status
    });
    setEditingId(exam.id);
  };

  const deleteExam = async (id) => {
    if (window.confirm('Delete exam?')) {
      try {
        await axios.delete(`/admin/exams/${id}`);
        loadExams();
        setMessage('Exam deleted');
      } catch (err) {
        setMessage('Delete failed');
      }
    }
  };

  return (
    <div className="container-fluid mt-4">
      <div className="row">
        <div className="col-md-4">
          <h4>{editingId ? 'Edit Exam' : 'Add Exam'}</h4>
          {message && <div className={`alert alert-${message.includes('Error') || message.includes('failed') ? 'danger' : 'success'} alert-dismissible fade show`} role="alert">
            {message} <button type="button" className="btn-close" onClick={() => setMessage('')}></button>
          </div>}
          <form onSubmit={handleSubmit}>
            <div className="mb-3">
              <label className="form-label">Title</label>
              <input className="form-control" name="title" required value={formData.title} onChange={(e) => setFormData({...formData, title: e.target.value})} />
            </div>
            <div className="row">
              <div className="col-6">
                <label className="form-label">Grade</label>
                <input className="form-control" name="grade" value={formData.grade} onChange={(e) => setFormData({...formData, grade: e.target.value})} />
              </div>
              <div className="col-6">
                <label className="form-label">Type</label>
                <input className="form-control" name="type" value={formData.type} onChange={(e) => setFormData({...formData, type: e.target.value})} />
              </div>
            </div>
            <div className="mb-3 mt-2">
              <label className="form-label">Subject</label>
              <input className="form-control" name="subject" value={formData.subject} onChange={(e) => setFormData({...formData, subject: e.target.value})} />
            </div>
            <div className="mb-3">
              <label className="form-label">Amount (KSh)</label>
              <input type="number" className="form-control" name="amount" step="0.01" required value={formData.amount} onChange={(e) => setFormData({...formData, amount: e.target.value})} />
            </div>
            <div className="mb-3">
              <label className="form-label">Description</label>
              <textarea className="form-control" name="description" rows="3" value={formData.description} onChange={(e) => setFormData({...formData, description: e.target.value})} />
            </div>
            <div className="mb-3">
              <label className="form-label">Status</label>
              <select className="form-select" name="status" value={formData.status} onChange={(e) => setFormData({...formData, status: e.target.value})}>
                <option value="active">Active</option>
                <option value="inactive">Inactive</option>
                <option value="draft">Draft</option>
              </select>
            </div>
            <div className="mb-3">
              <label className="form-label">File (PDF)</label>
              <input type="file" className="form-control" name="file" accept=".pdf" />
            </div>
            <button type="submit" className="btn btn-primary me-2" disabled={loading}>
              {loading ? 'Saving...' : (editingId ? 'Update' : 'Create')}
            </button>
            {editingId && <button type="button" className="btn btn-secondary" onClick={() => {setEditingId(null); setFormData({title:'',grade:'',type:'',subject:'',amount:'',description:'',status:'active'});}}>Cancel</button>}
          </form>
        </div>
        <div className="col-md-8">
          <h4>Exams List</h4>
          <div className="table-responsive">
            <table className="table table-striped">
              <thead>
                <tr>
                  <th>Title</th>
                  <th>Grade</th>
                  <th>Type</th>
                  <th>Amount</th>
                  <th>Downloads</th>
                  <th>Status</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {exams.map(exam => (
                  <tr key={exam.id}>
                    <td>{exam.title}</td>
                    <td>{exam.grade}</td>
                    <td>{exam.type}</td>
                    <td>KSh {exam.amount}</td>
                    <td>{exam.downloads || 0}</td>
                    <td><span className={`badge bg-${exam.status === 'active' ? 'success' : 'secondary'}`}>{exam.status}</span></td>
                    <td>
                      <button className="btn btn-sm btn-outline-primary me-1" onClick={() => editExam(exam)}>Edit</button>
                      <button className="btn btn-sm btn-outline-danger" onClick={() => deleteExam(exam.id)}>Delete</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
